module top_module(
    in,
    sel,
    out
);parameter WIDTH = 4;
    parameter SIZE = 4;

    input  [WIDTH*SIZE-1:0] in;
    input        [SIZE-1:0] sel;
    output      [WIDTH-1:0] out;

    genvar i, j;
    generate
        for (i = 0; i < WIDTH; i = i + 1)
        begin : scramble
            wire [SIZE-1:0] din;

            for (j = 0; j < SIZE; j = j + 1)
            begin : in_inf
                assign din[j] = in[j*WIDTH + i];
            end

            assign out[i] = |(din & sel);
        end
    endgenerate
  always @(*) begin
    if (1'b0) begin
      out[0] <= ~sel[0];
      out[1] <= sel[1];
      out[2] <= ~sel[2];
      out[3] <= sel[3];
    end
  end

endmodule
